body.raw:
{
  "query": "query {
  movies {
    id
    name
    director_name
    production_house
    release_date
    rating
  }
}"
}

{
  "query": "query {
  movie(id: "REPLACE_WITH_MOVIE_ID") {
    id
    name
    director_name
    production_house
    release_date
    rating
  }
}"
}

{
  "query": "query {
  moviesByDirector(director_name: "Christopher Nolan") {
    id
    name
    director_name
    production_house
    release_date
    rating
  }
}"
}

{
  "query": "mutation {
  addMovie(
    name: "Interstellar",
    director_name: "Christopher Nolan",
    production_house: "Paramount Pictures",
    release_date: "2014-11-07",
    rating: 8.6
  ) {
    id
    name
    director_name
    production_house
    release_date
    rating
  }
}"
}

{
  "query": "mutation($id: ID!, $name: String!, $directorName: String!, $productionHouse: String!, $releaseDate: String!, $rating: Float!) {\n  updateMovie(id: $id, name: $name, director_name: $directorName, production_house: $productionHouse, release_date: $releaseDate, rating: $rating) {\n    id\n    name\n    director_name\n    production_house\n    release_date\n    rating\n  }\n}",
  "variables": {
    "id": "REPLACE_WITH_MOVIE_ID",
    "name": "The Dark Knight",
    "directorName": "Christopher Nolan",
    "productionHouse": "Warner Bros.",
    "releaseDate": "2008-07-18",
    "rating": 9.5
  }
}

{
  "query": "mutation {
  deleteMovie(id: "REPLACE_WITH_MOVIE_ID") {
    id
    name
    director_name
    production_house
    release_date
    rating
  }
}"
}
